import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:4000';

function UploadContent({ onAdd }) {
  const [title, setTitle] = useState('');
  const [summary, setSummary] = useState('');
  const [file, setFile] = useState(null);
  const [previewImage, setPreviewImage] = useState(null);
  const navigate = useNavigate();

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleImageChange = (e) => {
    if (e.target.files.length > 0) {
      setPreviewImage(e.target.files[0]);
    }
  };

  const handleUpload = async () => {
    if (!file || !title.trim() || !summary.trim()) {
      alert('Please fill in all fields and select a file.');
      return;
    }

    const formData = new FormData();
    formData.append('file', file);
    formData.append('previewImage', previewImage);
    formData.append('title', title);
    formData.append('summary', summary);

    if (previewImage) {
      formData.append('previewImage', previewImage);
    }

    try {
      const response = await fetch(`${BASE_URL}/upload`, {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) throw new Error('Upload failed');

      const newPost = await response.json();
      onAdd(newPost);
      navigate('/');
    } catch (err) {
      console.error('Upload failed:', err);
      alert('Something went wrong while uploading.');
    }
  };

  return (
    <div style={{ padding: '2rem', maxWidth: '600px', margin: '0 auto' }}>
      <h2 style={{ marginBottom: '1rem' }}>Upload Word or PDF</h2>

      <input
        type="text"
        placeholder="Title"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
        style={{ width: '100%', padding: '0.5rem', marginBottom: '1rem' }}
      />

      <input
        type="text"
        placeholder="Short Summary"
        value={summary}
        onChange={(e) => setSummary(e.target.value)}
        style={{ width: '100%', padding: '0.5rem', marginBottom: '1rem' }}
      />

      <label style={{ fontWeight: 'bold' }}>Upload Word or PDF:</label>
      <input
        type="file"
        accept=".pdf,.docx"
        onChange={handleFileChange}
        style={{ marginBottom: '1rem', display: 'block' }}
      />

      <label style={{ fontWeight: 'bold' }}>Upload Preview Image:</label>
      <input
        type="file"
        accept="image/*"
        onChange={handleImageChange}
        style={{ marginBottom: '1rem', display: 'block' }}
      />

      <button
        onClick={handleUpload}
        style={{
          backgroundColor: '#10b981',
          color: 'white',
          padding: '0.7rem 1.5rem',
          border: 'none',
          borderRadius: '6px',
          cursor: 'pointer',
          fontWeight: 'bold',
        }}
      >
        Upload
      </button>
    </div>
  );
}

export default UploadContent;
